// Only trigger the doorbell on button press, ignore release
var data = msg.payload;
if (!data || data.state !== 'pressed') {
    return null;
}

// This is the exact message format the Doorbell Function node expects
return {
    topic: 'doorbell_press',
    payload: true
};

var data = msg.payload;
var count = (data && data.count !== undefined) ? data.count : '?';

// Output 1: Motion Detected (existing Status Indicator expects this string)
var motionMsg = { payload: 'Motion DETECTED' };

// Output 2: Heartbeat counter for the QPG6200 Device group
var counterMsg = { payload: '💓 ' + count };

return [motionMsg, counterMsg];

var data = msg.payload;
var connected = data && data.connected === true;
var device = (data && data.device) ? data.device : 'QPG6200';

// Output 1: Speaker UI expects true (active) or false (inactive)
var speakerMsg = { payload: connected };

// Output 2: Human-readable status for the QPG6200 Device group
var statusMsg = {
    payload: connected
        ? ('✅ Connected – ' + device)
        : ('❌ Disconnected – ' + device)
};

return [speakerMsg, statusMsg];

// The Light Switch sends 'Motion DETECTED' (on) or 'No motion detected' (off)
if (msg.payload === 'Motion DETECTED') {
    msg.payload = JSON.stringify({ led: 'on' });
} else {
    msg.payload = JSON.stringify({ led: 'off' });
}
return msg;

// Flash the QPG6200 BLUE LED for 3 seconds on doorbell ring
node.send({ payload: JSON.stringify({ led: 'on' }) });

setTimeout(function() {
    node.send({ payload: JSON.stringify({ led: 'off' }) });
}, 3000);

return null;

let username = msg.payload.username || "";
let password = msg.payload.password || "";

if (username === "admin" && password === "Qorvo") {
    flow.set("loggedIn", true);
    flow.set("logoutAt", Date.now() + 5 *60 * 1000);

    msg.payload = { status: "success" };
    return msg;
} else {
    flow.set("loggedIn", false);
    flow.set("logoutAt", null);

    msg.payload = { status: "fail" };
    return msg;
}

if (msg.payload && msg.payload.status === "success") {
    flow.set("loggedIn", true);
    let oldTimer = flow.get("logoutTimer");
    if (oldTimer) clearTimeout(oldTimer);
    let timer = setTimeout(() => {
        flow.set("loggedIn", false);
        node.send({ payload: { page: "Login", pages: { hide: ["Smart Door Devices"], show: ["Login"] } } });
    }, 5 * 60 * 1000);
    flow.set("logoutTimer", timer);
    msg.payload = { page: "Smart Door Devices", pages: { hide: ["Login"], show: ["Smart Door Devices"] }, justLoggedIn: true };
    return msg;
}
return null;

flow.set("loggedIn", false);
flow.set("logoutAt", null);

msg.payload = { page: "Login" };
return msg;

let loggedIn = flow.get("loggedIn") || false;
if (!loggedIn) {
    msg.payload = { page: "Login" };
    return msg;
}
return null;

