if (msg.topic === "doorbell_press") {
    node.send([
        { topic: "doorbell_state", payload: "🔔 Door bell ringing" },
        { payload: true }
    ]);
    setTimeout(() => {
        node.send([
            { topic: "doorbell_state" },
            { payload: false }
        ]);
    }, 3000);
}
return null;

let logoutAt = flow.get("logoutAt");
let loggedIn = flow.get("loggedIn");

if (loggedIn && logoutAt && Date.now() >= logoutAt) {
    flow.set("loggedIn", false);
    flow.set("logoutAt", null);

    return [
        { payload: { page: "Login" } },
        null
    ];
}

return [
    null,
    { logoutAt: logoutAt }
];

flow.set("loggedIn", false);
flow.set("logoutAt", null);

msg.payload = { page: "Login" };
return msg;

let loggedIn = flow.get("loggedIn") || false;
if (!loggedIn) {
    msg.payload = { page: "Login" };
    return msg;
}
return null;
